#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e4+5;
int n,a[MAXN];
ll ans;
int main(void){
    n=read();
    for(int i=1;i<=n;++i)
    {
        a[i]=read();
    }
    sort(a+1,a+n+1);
    for(int i=1;i<=n;++i)
    {
        for(int j=i+1,k=i+1;j<=n;++j)
        {
            while(k<n&&a[i]+a[j]>a[k+1])++k;
            ans+=k-j;
        }
    }
    write(ans);
	return false;
}
